// ════════════════════════════════════════════════════════
// TOOL: BUSCAR TODOS OS SERVIÇOS
// Lista todos os serviços agrupados por categoria
// ════════════════════════════════════════════════════════

const input = $input.item.json;
const organizacaoId = input.organizacao_id || input.organizacaoId;

if (!organizacaoId) {
  return [{ json: { error: true, message: 'organizacao_id não informado.' } }];
}

return [{ json: { organizacao_id: organizacaoId } }];

// Formatar e agrupar serviços por categoria
const items = $input.all();
const servicos = items
  .map(item => item.json)
  .filter(item => item.servico_id);

if (servicos.length === 0) {
  return [{
    json: {
      response: JSON.stringify({
        categorias: [],
        mensagem: 'Nenhum serviço disponível no momento.'
      })
    }
  }];
}

// Agrupar por categoria
const porCategoria = {};
servicos.forEach(s => {
  const cat = s.categoria || 'Outros';
  if (!porCategoria[cat]) {
    porCategoria[cat] = {
      categoria: cat,
      categoria_id: s.categoria_id,
      servicos: []
    };
  }
  porCategoria[cat].servicos.push({
    servico_id: s.servico_id,
    nome: s.nome,
    preco: `R$ ${parseFloat(s.preco || 0).toFixed(2).replace('.', ',')}`,
    preco_valor: parseFloat(s.preco || 0),
    duracao: `${s.duracao} min`,
    duracao_minutos: s.duracao,
    descricao: s.descricao || ''
  });
});

return [{
  json: {
    response: JSON.stringify({
      categorias: Object.values(porCategoria),
      total_servicos: servicos.length
    })
  }
}];
